"use strict";(self.webpackChunkclassroom_scrapper_site=self.webpackChunkclassroom_scrapper_site||[]).push([[2420],{57528(a){a.exports=JSON.parse('{"tag":{"label":"Random Variables","permalink":"/classroom-scrapper/tags/random-variables","allTagsPath":"/classroom-scrapper/tags","count":8,"items":[{"id":"ES 114 Probability, Statistics and Data Visualisation/Random Variables/Lec_09_Cumulative Distribution Functions Discrete Case","title":"Cumulative Distribution Functions (Discrete Case)","description":"1. Introduction: Generating Arbitrary Random Numbers","permalink":"/classroom-scrapper/ES 114 Probability, Statistics and Data Visualisation/Random Variables/Lec_09_Cumulative Distribution Functions Discrete Case"},{"id":"ES 114 Probability, Statistics and Data Visualisation/Random Variables/Lec_13_Expectation of Continuous Random Variables","title":"Expectation of Continuous Random Variables","description":"In previous lectures, we established the framework for continuous random variables and their Probability Density Functions (PDFs). Today, we delve into one of the most fundamental concepts in probability theory: Expectation, which represents the average or mean value of a random variable.","permalink":"/classroom-scrapper/ES 114 Probability, Statistics and Data Visualisation/Random Variables/Lec_13_Expectation of Continuous Random Variables"},{"id":"ES 114 Probability, Statistics and Data Visualisation/Random Variables/Lec_10_Expectation of Random Variables","title":"Expectation of Random Variables","description":"The concept of expectation is fundamental in probability theory, representing the \\"average\\" value of a random variable. It\'s not just a simple average but a weighted average, where each possible value of the random variable is weighted by its probability.","permalink":"/classroom-scrapper/ES 114 Probability, Statistics and Data Visualisation/Random Variables/Lec_10_Expectation of Random Variables"},{"id":"ES 114 Probability, Statistics and Data Visualisation/Random Variables/Lec_15_Joint Expectation and Correlation","title":"Joint Expectation","description":"Definition of Joint Expectation","permalink":"/classroom-scrapper/ES 114 Probability, Statistics and Data Visualisation/Random Variables/Lec_15_Joint Expectation and Correlation"},{"id":"ES 114 Probability, Statistics and Data Visualisation/Random Variables/Lec_14_Joint Probability Distributions","title":"Joint PDF and CDF","description":"Introduction to Joint Distributions","permalink":"/classroom-scrapper/ES 114 Probability, Statistics and Data Visualisation/Random Variables/Lec_14_Joint Probability Distributions"},{"id":"ES 114 Probability, Statistics and Data Visualisation/Random Variables/Lec_11_Moments and Variance of Random Variables","title":"Moments and Variance of Random Variables","description":"This lecture extends the concept of expectation by introducing moments and variance, fundamental measures for characterizing random variables. We begin by reviewing essential properties of expectation.","permalink":"/classroom-scrapper/ES 114 Probability, Statistics and Data Visualisation/Random Variables/Lec_11_Moments and Variance of Random Variables"},{"id":"ES 114 Probability, Statistics and Data Visualisation/Random Variables/Lec_08_Probability Mass Functions","title":"Probability Mass Functions (PMF)","description":"---","permalink":"/classroom-scrapper/ES 114 Probability, Statistics and Data Visualisation/Random Variables/Lec_08_Probability Mass Functions"},{"id":"ES 114 Probability, Statistics and Data Visualisation/Random Variables/Lec_07_Introduction to Random Variables","title":"Random Variables Introduction","description":"In probability theory, experiments often yield outcomes that are descriptive rather than inherently numerical (e.g., \\"Head,\\" \\"Tail,\\" \\"rainy,\\" \\"sunny\\"). While these can be analyzed directly, mathematical operations like averaging or calculating variance become complex. Random variables serve as a crucial bridge, translating these descriptive outcomes into numerical values, thereby simplifying mathematical analysis.","permalink":"/classroom-scrapper/ES 114 Probability, Statistics and Data Visualisation/Random Variables/Lec_07_Introduction to Random Variables"}],"unlisted":false}}')}}]);